+        return new;
+    }
+
+    /// Except (rows in first but not second).
+    pub fn except(self: *const Self, other: *const DataFrame) Self {
+        var new = self.*;
+        new.set_op = .{
+            .other = other,
+            .op_type = .except,
+        };
+        return new;
+    }
